{"code": "import re

clinical_data = env['data_1']
mutation_data = env['data_2']

mutated_barcodes = {row['ParticipantBarcode'] for row in mutation_data}

total_counts = {}
mutated_counts = {}

for row in clinical_data:
    desc = row.get('Patient_description', '')
    hist_type = row.get('histological_type', '')

    if not hist_type or hist_type.startswith('['):
        continue

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        barcode = match.group(0)

        total_counts[hist_type] = total_counts.get(hist_type, 0) + 1
        if barcode in mutated_barcodes:
            mutated_counts[hist_type] = mutated_counts.get(hist_type, 0) + 1

results = []
for hist_type, total in total_counts.items():
    mutated = mutated_counts.get(hist_type, 0)
    pct = (mutated / total) * 100
    results.append((hist_type, pct, mutated, total))

results.sort(key=lambda x: x[1], reverse=True)

print(f"Total clinical rows: {len(clinical_data)}")
print(f"Total mutated barcodes: {len(mutated_barcodes)}")
print("Top 3 histological types by CDH1 mutation percentage:")
for i, (hist_type, pct, mut, tot) in enumerate(results[:3]):
    print(f"{i+1}. {hist_type}: {pct:.2f}% ({mut}/{tot})")
"}

